import React from "react";
import { Link } from "react-router-dom";
import "./Section.css";

function Home() {
  return (
    <div>
      <h1>HEALink</h1>

      {/* Sections Grid */}
      <div className="sections">
        <Link to="/pathology" className="section-card">
          <h3>Pathology</h3>
        </Link>

        <Link to="/blood-bank" className="section-card">
          <h3>Blood Bank</h3>
        </Link>

        <Link to="/consultancy" className="section-card">
          <h3>Consultancy</h3>
        </Link>

        <Link to="/medicine" className="section-card">
          <h3>Medicine Delivery</h3>
        </Link>
      </div>

      {/* Auth Buttons */}
      <div className="auth-buttons">
        <Link to="/login"><button>Login</button></Link>
        <Link to="/register"><button>Register</button></Link>
      </div>
    </div>
  );
}

export default Home;
